#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int abs(int x) { return x < 0 ? -x : x; }

int main() {
    int N;
    scanf("%d", &N);
    int Ax, Ay, Bx, By;
    scanf("%d %d", &Ax, &Ay);
    scanf("%d %d", &Bx, &By);
    int* dpA = (int*)malloc(N * sizeof(int));
    int* dpB = (int*)malloc(N * sizeof(int));
    int* x = (int*)malloc(N * sizeof(int));
    int* y = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    dpA[0] = abs(x[0] - Ax) + abs(y[0] - Ay);
    dpB[0] = abs(x[0] - Bx) + abs(y[0] - By);
    for (int i = 1; i < N; i++) {
        dpA[i] = min(dpA[i-1] + abs(x[i] - x[i-1]) + abs(y[i] - y[i-1]), dpB[i-1] + abs(x[i] - x[i-1]) + abs(y[i] - y[i-1]) + abs(x[i-1] - Ax) + abs(y[i-1] - Ay));
        dpB[i] = min(dpB[i-1] + abs(x[i] - x[i-1]) + abs(y[i] - y[i-1]), dpA[i-1] + abs(x[i] - x[i-1]) + abs(y[i] - y[i-1]) + abs(x[i-1] - Bx) + abs(y[i-1] - By));
    }
    printf("%d\n", min(dpA[N-1], dpB[N-1]));
    free(dpA);
    free(dpB);
    free(x);
    free(y);
    return 0;
}

