        for (int i = 1; i < N; i++) {
            dpA[i] = Math.min(dpA[i-1] + Math.abs(x[i] - x[i-1]) + Math.abs(y[i] - y[i-1]), dpB[i-1] + Math.abs(x[i] - x[i-1]) + Math.abs(y[i] - y[i-1]) + Math.abs(x[i-1] - Ax) + Math.abs(y[i-1] - Ay));
